mapper.select:
/* 챗 가이드 타입/키로 GUIDE_ID 조회 chatGuide.selectGuideIdByTypeAndKey */
SELECT
    A.GUIDE_ID
FROM TB_CHAT_GUIDE A
WHERE 1=1
  AND A.GUIDE_TP_CD = #{guideTpCd}
  AND A.GUIDE_KEY = #{guideKey}
LIMIT 1

mapper.insert:
/* 챗 가이드 인사멘트 등록/수정 chatGuide.insertChatGuideGreetingList */
INSERT INTO TB_CHAT_GUIDE (
    GUIDE_ID
    , GUIDE_TP_CD
    , GUIDE_KEY
    , ENBL_YN
    , CONTENT
    , MODIFY_DT
) VALUES (
    #{guideId}
    , '001'
    , #{guideKey}
    , #{enblYn}
    , #{content}
    , NOW()
)
ON DUPLICATE KEY UPDATE
    GUIDE_TP_CD = '001'
    , ENBL_YN = VALUES(ENBL_YN)
    , CONTENT = VALUES(CONTENT)
    , MODIFY_DT = NOW()

/* 챗 가이드 안내멘트 등록/수정 chatGuide.insertChatGuideNoticeList */
INSERT INTO TB_CHAT_GUIDE (
    GUIDE_ID
    , GUIDE_TP_CD
    , GUIDE_KEY
    , ENBL_YN
    , CONTENT
    , DSPL_COND
    , AUTO_DETECT_YN
    , MODIFY_DT
) VALUES (
    #{guideId}
    , '002'
    , #{guideKey}
    , #{enblYn}
    , #{content}
    , #{dsplCond}
    , #{autoDetectYn}
    , NOW()
)
ON DUPLICATE KEY UPDATE
    GUIDE_TP_CD = '002'
    , ENBL_YN = VALUES(ENBL_YN)
    , CONTENT = VALUES(CONTENT)
    , DSPL_COND = VALUES(DSPL_COND)
    , AUTO_DETECT_YN = VALUES(AUTO_DETECT_YN)
    , MODIFY_DT = NOW()

/* 챗 가이드 오류메시지 등록/수정 chatGuide.insertChatGuideErrorMessageList */
INSERT INTO TB_CHAT_GUIDE (
    GUIDE_ID
    , GUIDE_TP_CD
    , GUIDE_KEY
    , ENBL_YN
    , CONTENT
    , MAX_CHARS
    , MODIFY_DT
) VALUES (
    #{guideId}
    , '003'
    , #{guideKey}
    , #{enblYn}
    , #{content}
    , #{maxChars}
    , NOW()
)
ON DUPLICATE KEY UPDATE
    GUIDE_TP_CD = '003'
    , ENBL_YN = VALUES(ENBL_YN)
    , CONTENT = VALUES(CONTENT)
    , MAX_CHARS = VALUES(MAX_CHARS)
    , MODIFY_DT = NOW()

/* 챗 가이드 점검/장애 등록/수정 chatGuide.insertChatGuideMaintenanceList */
INSERT INTO TB_CHAT_GUIDE (
    GUIDE_ID
    , GUIDE_TP_CD
    , GUIDE_KEY
    , TITLE
    , ENBL_YN
    , CONTENT
    , START_DT
    , END_DT
    , ADVANCE_NOTICE_CD
    , AUTO_DSPL_YN
    , MODIFY_DT
) VALUES (
    #{guideId}
    , '004'
    , #{guideKey}
    , #{title}
    , #{enblYn}
    , #{content}
    , #{startDt}
    , #{endDt}
    , #{advanceNoticeCd}
    , #{autoDsplYn}
    , NOW()
)
ON DUPLICATE KEY UPDATE
    GUIDE_TP_CD = '004'
    , TITLE = VALUES(TITLE)
    , ENBL_YN = VALUES(ENBL_YN)
    , CONTENT = VALUES(CONTENT)
    , START_DT = VALUES(START_DT)
    , END_DT = VALUES(END_DT)
    , ADVANCE_NOTICE_CD = VALUES(ADVANCE_NOTICE_CD)
    , AUTO_DSPL_YN = VALUES(AUTO_DSPL_YN)
    , MODIFY_DT = NOW()
